import{_ as e,o as a,c as t,ag as r}from"./chunks/framework.wqPkq5Rj.js";const g=JSON.parse('{"title":"从 Notion / Google Drive 迁过来","description":"","frontmatter":{},"headers":[],"relativePath":"setup/import.md","filePath":"setup/import.md","lastUpdated":1777169627000}'),l={name:"setup/import.md"};function i(n,o,s,p,c,d){return a(),t("div",null,[...o[0]||(o[0]=[r('<h1 id="从-notion-google-drive-迁过来" tabindex="-1">从 Notion / Google Drive 迁过来 <a class="header-anchor" href="#从-notion-google-drive-迁过来" aria-label="Permalink to &quot;从 Notion / Google Drive 迁过来&quot;">​</a></h1><h2 id="从-notion-迁" tabindex="-1">从 Notion 迁 <a class="header-anchor" href="#从-notion-迁" aria-label="Permalink to &quot;从 Notion 迁&quot;">​</a></h2><h3 id="方式一-导出单个页面" tabindex="-1">方式一：导出单个页面 <a class="header-anchor" href="#方式一-导出单个页面" aria-label="Permalink to &quot;方式一：导出单个页面&quot;">​</a></h3><p>适合只迁移部分内容。</p><ol><li>打开要导出的 Notion 页面</li><li>点击右上角 <strong>···</strong> 菜单 → 「Export」</li><li>弹窗中格式选 <strong>Markdown &amp; CSV</strong>（AI 读 Markdown 效率最高，不要选 HTML）</li><li>如需包含子页面，打开「Include subpages」</li><li>点击 Export，下载 zip 文件</li></ol><blockquote><p>Database 会导出为 CSV 文件；Callout 块会以 HTML 格式保留（Markdown 无等价格式）。</p></blockquote><h3 id="方式二-导出整个-workspace" tabindex="-1">方式二：导出整个 Workspace <a class="header-anchor" href="#方式二-导出整个-workspace" aria-label="Permalink to &quot;方式二：导出整个 Workspace&quot;">​</a></h3><p>适合整体迁移，一次把所有内容打包。</p><p><strong>权限要求</strong>：需要是 Workspace <strong>Owner</strong>（所有者）才能执行整体导出。</p><ol><li>打开 Notion，进入「Settings」→「General」</li><li>找到「Export all workspace content」，点击导出</li><li>Notion 会发一封邮件给你，里面有下载链接（链接 7 天内有效）</li></ol><blockquote><p>导出处理最长需要 30 小时，取决于 workspace 体量。</p></blockquote><hr><h2 id="从-google-drive-迁" tabindex="-1">从 Google Drive 迁 <a class="header-anchor" href="#从-google-drive-迁" aria-label="Permalink to &quot;从 Google Drive 迁&quot;">​</a></h2><h3 id="方式一-选中文件下载" tabindex="-1">方式一：选中文件下载 <a class="header-anchor" href="#方式一-选中文件下载" aria-label="Permalink to &quot;方式一：选中文件下载&quot;">​</a></h3><p>适合只迁移部分内容。所有文件类型均支持。</p><ol><li>单击选中文件；按住 <code>Ctrl</code>（Mac 为 <code>⌘</code>）可多选，也可框选一批</li><li>右键 → 「Download」，打包下载</li></ol><blockquote><p>Google Docs / Sheets / Slides 会自动转换格式下载（Docs → <code>.docx</code>，Sheets → <code>.xlsx</code>，Slides → <code>.pptx</code>）。</p></blockquote><h3 id="方式二-导出整个-google-drive" tabindex="-1">方式二：导出整个 Google Drive <a class="header-anchor" href="#方式二-导出整个-google-drive" aria-label="Permalink to &quot;方式二：导出整个 Google Drive&quot;">​</a></h3><p>适合整体迁移，通过 Google Takeout 打包下载。</p><ol><li>前往 <a href="https://takeout.google.com" target="_blank" rel="noreferrer">takeout.google.com</a></li><li>取消全选，只勾选「Drive」</li><li>选择导出格式和频率，点击「Create export」</li><li>Google 会发邮件通知你下载链接（视数据量，处理时间从几分钟到数小时不等）</li></ol><hr><h2 id="导入-moxt" tabindex="-1">导入 Moxt <a class="header-anchor" href="#导入-moxt" aria-label="Permalink to &quot;导入 Moxt&quot;">​</a></h2><p>有两个入口，选其一：</p><ul><li><strong>方式 A</strong>：点击左侧边栏 Team Space 或 Personal Space 旁的 <strong>+</strong></li><li><strong>方式 B</strong>：点击任意文件夹旁的 <strong>···</strong> 菜单</li></ul><p>进入后选择「导入」，弹窗打开后将导出的文件拖拽上传即可。</p><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Notion Database 的视图（看板、日历）会保留吗？</strong></p><p>不会。Database 导出为 CSV，数据和字段都在，但视图样式不保留。迁入 Moxt 后可以让 momo 重新生成 HTML 可视化。</p><p><strong>导入之后 AI 就能读这些内容了吗？</strong></p><p>是的。导入完成后 momo 就能访问这些文档。你可以问它：「我们之前有一篇关于 [某个主题] 的文档，你能找到并总结一下吗？」</p>',31)])])}const u=e(l,[["render",i]]);export{g as __pageData,u as default};
